func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for jj := 0; jj < orderCount; jj++ {
		bestAssignIdx := -1
		bestDelta := math.MaxFloat64
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj
		maxTryAssigns := dispatch.AssignsLen
		if maxTryAssigns == 0 {
			maxTryAssigns = 1
		}
		for tryIdx := 0; tryIdx <= maxTryAssigns; tryIdx++ {
			assignPtr := &dispatch.Assigns[tryIdx]
			oldCost := assignPtr.Cost
			savedState := *assignPtr
