	orderCount := len(oris)
	for jj := 0; jj < orderCount; jj++ {
		bestAssignIdx := -1
		bestScore := math.MaxFloat64
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj
		currentActiveAssigns := dispatch.AssignsLen
		if currentActiveAssigns > MAXASSIGNS {
			currentActiveAssigns = MAXASSIGNS
		}
		for tryIdx := 0; tryIdx < currentActiveAssigns; tryIdx++ {
			assignPtr := &dispatch.Assigns[tryIdx]
			oldCost := assignPtr.Cost
			savedState := *assignPtr
			if assignPtr.AddShip(shipID, ori, des) {
				assignPtr.GenRoute()
				newCost := assignPtr.Cost
				if newCost >= 0 && oldCost >= 0 {
					costIncrease := newCost - oldCost
					utilizationPenalty := 0.0
					if len(assignPtr.Stations) > 0 {
						stationCount := float64(len(assignPtr.Stations))
						utilizationPenalty = 100.0 / stationCount
					}
					waitTimePenalty := 0.0
					timeWindowDiff := ori.TimeEnd - ori.TimeStart
					if timeWindowDiff > 0 {
						waitTimePenalty = float64(timeWindowDiff) * 0.05
					}
					score := costIncrease + utilizationPenalty + waitTimePenalty
					if score < bestScore {
						bestScore = score
						bestAssignIdx = tryIdx
					}
				}
			}
			*assignPtr = savedState
			assignPtr.GenRoute()
		}
		fallbackIdx := -1
		if bestAssignIdx == -1 {
			foundEmptySlot := false
			for idx := 0; idx < MAXASSIGNS; idx++ {
				tempPtr := &dispatch.Assigns[idx]
				if tempPtr.Cost < 0 || len(tempPtr.Stations) == 0 {
					fallbackIdx = idx
					foundEmptySlot = true
					break
				}
			}
			if !foundEmptySlot {
				if dispatch.AssignsLen < MAXASSIGNS {
					fallbackIdx = dispatch.AssignsLen
					dispatch.AssignsLen++
				} else {
					minLoadIndex := 0
					minLoad := float64(MAXASSIGNS + 1)
					for k := 0; k < MAXASSIGNS; k++ {
						loadVal := float64(len(dispatch.Assigns[k].Stations))
						if loadVal < minLoad {
							minLoad = loadVal
							minLoadIndex = k
						}
					}
					fallbackIdx = minLoadIndex
				}
			}
